 1	import React, { useState } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { IoK8sApiBatchV1Job, IoK8sApiCoreV1ConfigMap } from '@kubevirt-ui/kubevirt-api/kubernetes';
 5	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 6	import DropdownToggle from '@kubevirt-utils/components/toggles/DropdownToggle';
 7	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
10	import { Dropdown, DropdownItem, DropdownList } from '@patternfly/react-core';
11	
12	import DeleteCheckupModal from '../../components/DeleteCheckupModal';
13	import { STATUS_SUCCEEDED } from '../../utils/utils';
14	import { deleteStorageCheckup, rerunStorageCheckup } from '../utils/utils';
15	
16	const CheckupsStorageActions = ({
17	  configMap,
18	  isKebab = false,
19	  jobs,
20	}: {
21	  configMap: IoK8sApiCoreV1ConfigMap;
22	  isKebab?: boolean;
23	  jobs: IoK8sApiBatchV1Job[];
24	}) => {
25	  const { t } = useKubevirtTranslation();
26	  const navigate = useNavigate();
27	  const { createModal } = useModal();
28	  const [isActionsOpen, setIsActionsOpen] = useState<boolean>(false);
29	
30	  const onToggle = () => setIsActionsOpen((prevIsOpen) => !prevIsOpen);
31	
32	  const Toggle = isKebab
33	    ? KebabToggle({ isExpanded: isActionsOpen, onClick: onToggle })
34	    : DropdownToggle({ isExpanded: isActionsOpen, onClick: onToggle, placeholder: t('Actions') });
35	
36	  const deleteCheckup = () => {
37	    setIsActionsOpen(false);
38	    deleteStorageCheckup(configMap, jobs);
39	    navigate(`/k8s/ns/${getNamespace(configMap)}/checkups/storage`);
40	  };
41	
42	  return (
43	    <Dropdown
44	      isOpen={isActionsOpen}
45	      onOpenChange={(open: boolean) => setIsActionsOpen(open)}
46	      toggle={Toggle}
47	    >
48	      <DropdownList>
49	        <DropdownItem
50	          onClick={() =>
51	            createModal((props) => (
52	              <DeleteCheckupModal
53	                {...props}
54	                name={getName(configMap)}
55	                namespace={getNamespace(configMap)}
56	                onDelete={deleteCheckup}
57	              />
58	            ))
59	          }
60	          key="delete"
61	        >
62	          {t('Delete')}
63	        </DropdownItem>
64	        <DropdownItem
65	          onClick={() => {
66	            setIsActionsOpen(false);
67	            return rerunStorageCheckup(configMap);
68	          }}
69	          isDisabled={configMap?.data?.[STATUS_SUCCEEDED] === undefined}
70	          key="rerun"
71	        >
72	          {t('Rerun')}
73	        </DropdownItem>
74	      </DropdownList>
75	    </Dropdown>
76	  );
77	};
78	
79	export default CheckupsStorageActions;

